css:
.loader {color: var(--loader-color, #2563eb);
  --loader-secondary-color: #38bdf8;
  --loader-bg: #ffffff;
  height: 70px;
  aspect-ratio: 1;
  padding: 10px;
  border-radius: 50%;
  box-sizing: border-box;
  position: relative;
  mask: conic-gradient(currentColor 0 0) content-box exclude,conic-gradient(currentColor 0 0);
  filter: blur(12px);
}.loader:before {content: "";
  position: absolute;
  inset: 0;
  background: repeating-conic-gradient(#0000 0 5%,var(--loader-color, #2563eb),#0000 20% 50%);
  animation: l2 1.5s linear infinite;
}@keyframes l2 {to {rotate: 1turn}}
